class Solution:
    def getSubarrayBeauty(self, nums, k, x):
        n = len(nums)
        result = []
        for i in range(k - 1, n):
            window = nums[i - k + 1:i + 1]
            negs = sorted(v for v in window if v < 0)
            if len(negs) >= x:
                result.append(negs[x - 1])
            else:
                result.append(0)
        return result

