class Solution:
    def getSubarrayBeauty(self, nums, k, x):
        counts = [0] * 51
        n = len(nums)
        result = []
        for i in range(n):
            if nums[i] < 0:
                counts[-nums[i]] += 1
            if i >= k:
                old = nums[i - k]
                if old < 0:
                    counts[-old] -= 1
            if i >= k - 1:
                remaining = x
                beauty = 0
                for v in range(50, 0, -1):
                    if counts[v] > 0:
                        remaining -= counts[v]
                        if remaining <= 0:
                            beauty = -v
                            break
                result.append(beauty)
        return result

