var getSubarrayBeauty = function(nums, k, x) {
    const counts = new Array(51).fill(0);
    const n = nums.length;
    const result = [];
    for (let i = 0; i < n; i++) {
        if (nums[i] < 0) counts[-nums[i]]++;
        if (i >= k) {
            const old = nums[i - k];
            if (old < 0) counts[-old]--;
        }
        if (i >= k - 1) {
            let remaining = x;
            let beauty = 0;
            for (let v = 50; v >= 1; v--) {
                if (counts[v] > 0) {
                    remaining -= counts[v];
                    if (remaining <= 0) {
                        beauty = -v;
                        break;
                    }
                }
            }
            result.push(beauty);
        }
    }
    return result;
};
